import torch
import torch.nn as nn
import torch.nn.functional as F

# Using built-in activations
class MLP(nn.Module):
    def __init__(self, in_dim, hidden, out_dim, activation="relu"):
        super().__init__()
        self.fc1 = nn.Linear(in_dim, hidden)
        self.fc2 = nn.Linear(hidden, out_dim)
        activations = {
            "relu":       nn.ReLU(),
            "leaky_relu": nn.LeakyReLU(negative_slope=0.01),
            "prelu":      nn.PReLU(),
            "elu":        nn.ELU(alpha=1.0),
            "selu":       nn.SELU(),
            "gelu":       nn.GELU(),
            "silu":       nn.SiLU(),
            "mish":       nn.Mish(),
        }
        self.act = activations[activation]

    def forward(self, x):
        return self.fc2(self.act(self.fc1(x)))

# Custom activation: channel-wise PReLU
class ChannelPReLU(nn.Module):
    def __init__(self, num_channels, init=0.25):
        super().__init__()
        self.slope = nn.Parameter(torch.full((num_channels,), init))

    def forward(self, x):  # x: (B, C, ...)
        slope = self.slope.view(1, -1, *([1] * (x.dim() - 2)))
        return torch.where(x >= 0, x, slope * x)

# Quick sanity check
if __name__ == "__main__":
    x = torch.randn(4, 32)
    for name in ["relu", "gelu", "silu", "mish"]:
        model = MLP(32, 64, 10, activation=name)
        out = model(x)
        print(f"{name:12s}: output shape {out.shape}, mean {out.mean():.4f}")
